from pathlib import Path
import openpyxl
import re
from datetime import datetime, date

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('**/ap_ledger.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'ap_ledger.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0], data_only=True)

    # Find Invoice Register sheet (case-insensitive)
    ir_sheet = None
    for name in wb.sheetnames:
        if 'invoice' in name.lower() and 'register' in name.lower():
            ir_sheet = wb[name]
            break

    if ir_sheet is None:
        return {'pass': False, 'score': 0.0, 'feedback': f'No Invoice Register sheet found. Sheets present: {wb.sheetnames}.'}

    target_invoice = 'INV-NGO-4471'

    def cell_str(c):
        if c is None:
            return ''
        return str(c).strip()

    def normalize_str(s):
        return str(s).strip().lower().replace('$', '').replace(',', '').replace(' ', '').replace('us$', '')

    def date_matches(cell_val, target_date_str):
        """Check if a cell value matches a target date like '2025-05-19'."""
        if cell_val is None:
            return False
        # If it's a datetime/date object
        if isinstance(cell_val, (datetime, date)):
            formatted = cell_val.strftime('%Y-%m-%d')
            if formatted == target_date_str:
                return True
        # String comparison
        s = str(cell_val).strip()
        if target_date_str in s:
            return True
        try:
            target_dt = datetime.strptime(target_date_str, '%Y-%m-%d').date()
        except ValueError:
            return False
        for fmt in ['%Y-%m-%d', '%m/%d/%Y', '%m-%d-%Y', '%d/%m/%Y', '%Y/%m/%d', '%B %d, %Y', '%b %d, %Y', '%m/%d/%y', '%d-%b-%Y', '%d-%b-%y']:
            try:
                parsed = datetime.strptime(s.split(' ')[0] if ' ' in s and ':' in s else s, fmt).date()
                if parsed == target_dt:
                    return True
            except (ValueError, IndexError):
                continue
        try:
            parsed = datetime.strptime(s, '%Y-%m-%d %H:%M:%S').date()
            if parsed == target_dt:
                return True
        except ValueError:
            pass
        return False

    def amount_matches(cell_val, target_amount=2030.0):
        if cell_val is None:
            return False
        if isinstance(cell_val, (int, float)):
            if abs(float(cell_val) - target_amount) < 0.015:
                return True
        val = normalize_str(cell_val)
        try:
            num = float(val)
            if abs(num - target_amount) < 0.015:
                return True
        except (ValueError, TypeError):
            pass
        if '2030' in str(cell_val):
            return True
        return False

    def status_matches(cell_val):
        if cell_val is None:
            return False
        s = cell_str(cell_val).lower().replace('-', ' ').replace('_', ' ')
        return 'on hold' in s or s in ['onhold', 'on hold']

    def hold_code_matches(cell_val):
        if cell_val is None:
            return False
        s = cell_str(cell_val).upper()
        return s == 'MATCH' or 'MATCH' in s.split()

    def gl_matches(cell_val):
        if cell_val is None:
            return False
        return '6200-010-2200' in cell_str(cell_val)

    def invoice_id_matches(cell_val):
        if cell_val is None:
            return False
        return target_invoice.lower() in cell_str(cell_val).lower()

    def vendor_id_matches(cell_val):
        if cell_val is None:
            return False
        return 'v-00229' in cell_str(cell_val).lower()

    def vendor_name_matches(cell_val):
        if cell_val is None:
            return False
        s = cell_str(cell_val).lower()
        return 'northgate' in s and 'office' in s

    def po_matches(cell_val):
        if cell_val is None:
            return False
        return 'po-2025-00884' in cell_str(cell_val).lower()

    # Define matchers for the 10 expected values
    matchers = [
        ('Invoice Number (INV-NGO-4471)', invoice_id_matches),
        ('Vendor ID (V-00229)', vendor_id_matches),
        ('Vendor Name (Northgate Office Solutions)', vendor_name_matches),
        ('Invoice Date (2025-05-19)', lambda c: date_matches(c, '2025-05-19')),
        ('Received Date (2025-05-21)', lambda c: date_matches(c, '2025-05-21')),
        ('PO Number (PO-2025-00884)', po_matches),
        ('Invoice Amount (2030.00)', amount_matches),
        ('Status (on hold)', status_matches),
        ('Hold Code (MATCH)', hold_code_matches),
        ('GL Code (6200-010-2200)', gl_matches),
    ]
    num_matchers = len(matchers)

    # Search for rows that contain the target invoice
    candidate_rows = []
    for row in ir_sheet.iter_rows(min_row=2, values_only=True):
        for c in row:
            if c is not None and target_invoice.lower() in str(c).strip().lower():
                candidate_rows.append(row)
                break

    if not candidate_rows:
        return {'pass': False, 'score': 0.0, 'feedback': f'No row with invoice number {target_invoice} found in Invoice Register sheet.'}

    best_score = 0
    best_checks = {}
    best_row_str = ''

    for row in candidate_rows:
        row_vals = list(row)
        row_strs = [cell_str(c) for c in row_vals]
        row_str_combined = ' | '.join(row_strs)

        # Try sequential matching: find contiguous subsequence of cells matching matchers in order
        best_seq_score = 0
        best_seq_checks = {}

        for start_col in range(len(row_vals)):
            if start_col + num_matchers > len(row_vals):
                break
            checks = {}
            seq_score = 0
            for i, (name, matcher) in enumerate(matchers):
                val = row_vals[start_col + i]
                result = matcher(val)
                checks[name] = result
                if result:
                    seq_score += 1
            if seq_score > best_seq_score:
                best_seq_score = seq_score
                best_seq_checks = checks

        # Also try loose approach: check each matcher against the whole row (non-sequential)
        loose_checks = {}
        loose_score = 0
        for name, matcher in matchers:
            found = any(matcher(c) for c in row_vals)
            loose_checks[name] = found
            if found:
                loose_score += 1

        # Use the better of sequential or loose for scoring
        if best_seq_score >= loose_score:
            row_score = best_seq_score
            row_checks = best_seq_checks
        else:
            row_score = loose_score
            row_checks = loose_checks

        if row_score > best_score:
            best_score = row_score
            best_checks = row_checks
            best_row_str = row_str_combined

    total_checks = num_matchers
    final_score = best_score / total_checks
    all_pass = all(best_checks.values()) and best_score == total_checks

    details = []
    for k, v in best_checks.items():
        details.append(f'{k}: {"PASS" if v else "FAIL"}')

    feedback = (f'Invoice Register row for {target_invoice} found. '
                f'Row contents: [{best_row_str}]. '
                f'Check results ({int(best_score)}/{total_checks}): {", ".join(details)}.')

    return {'pass': all_pass, 'score': final_score, 'feedback': feedback}

