from pathlib import Path
import openpyxl
import re
from datetime import datetime, date

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('**/match_log_2025_Q2.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'match_log_2025_Q2.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0], data_only=True)

    target_invoice = 'INV-NGO-4471'
    found_rows = []
    found_sheet = None

    for ws in wb.worksheets:
        for row in ws.iter_rows(values_only=True):
            row_strs = [str(c).strip() if c is not None else '' for c in row]
            if target_invoice in row_strs:
                found_rows.append(row)
                found_sheet = ws.title
                break
        if found_rows:
            break

    if not found_rows:
        return {'pass': False, 'score': 0.0, 'feedback': f'INV-NGO-4471 not found in any sheet of match_log_2025_Q2.xlsx'}

    raw_row = found_rows[0]

    def parse_num(val):
        """Strip $, commas, %, whitespace and convert to float."""
        s = str(val).replace('$', '').replace(',', '').replace('%', '').strip()
        return float(s)

    def normalize(val):
        """Return a cleaned string representation."""
        if val is None:
            return ''
        return str(val).strip()

    def check_date(val, expected_str):
        """Check if val represents the date 2025-05-21."""
        if isinstance(val, (datetime, date)):
            if isinstance(val, datetime):
                d = val.date()
            else:
                d = val
            return d == date(2025, 5, 21)
        s = normalize(val)
        for fmt in ['%Y-%m-%d', '%m/%d/%Y', '%m-%d-%Y', '%d/%m/%Y', '%Y/%m/%d', '%m/%d/%y']:
            try:
                parsed = datetime.strptime(s.split(' ')[0], fmt).date()
                if parsed == date(2025, 5, 21):
                    return True
            except:
                pass
        if '2025-05-21' in s or '05/21/2025' in s or '5/21/2025' in s or '21/05/2025' in s or '2025/05/21' in s:
            return True
        return False

    row_vals = [normalize(v) for v in raw_row]

    def find_in_row_str(expected):
        for v in row_vals:
            if v.lower() == expected.lower():
                return True
        return False

    def find_in_row_str_contains(expected):
        for v in row_vals:
            if expected.lower() in v.lower():
                return True
        return False

    # Collect all numeric values from the row
    numeric_cells = []
    for i, v in enumerate(raw_row):
        try:
            num = parse_num(v)
            numeric_cells.append((i, num, v))
        except:
            pass

    def find_exact_num_in_row(expected, tolerance=0.011, exclude_indices=None):
        if exclude_indices is None:
            exclude_indices = set()
        for i, num, raw in numeric_cells:
            if i not in exclude_indices and abs(num - expected) <= tolerance:
                return i, num, raw
        return None

    def find_pct_in_row(expected_pct, tolerance=0.5, exclude_indices=None):
        if exclude_indices is None:
            exclude_indices = set()
        for i, num, raw in numeric_cells:
            if i in exclude_indices:
                continue
            if abs(num - expected_pct) <= tolerance:
                return i, num, raw
            if abs(num * 100 - expected_pct) <= tolerance:
                return i, num, raw
        return None

    issues = []
    details = []
    used_indices = set()

    # 1. Date: 2025-05-21
    date_found = False
    for v in raw_row:
        if check_date(v, '2025-05-21'):
            date_found = True
            details.append(f'Date 2025-05-21: found \u2713')
            break
    if not date_found:
        issues.append(f'Date 2025-05-21 not found in row. Row values: {row_vals}')

    # 2. PO-2025-00884
    if find_in_row_str('PO-2025-00884'):
        details.append('PO Number PO-2025-00884: found \u2713')
    else:
        issues.append(f'PO-2025-00884 not found in row')

    # 3. V-00229
    if find_in_row_str('V-00229'):
        details.append('Vendor ID V-00229: found \u2713')
    else:
        issues.append(f'V-00229 not found in row')

    # 4. Northgate Office Solutions
    if find_in_row_str_contains('Northgate Office Solutions'):
        details.append('Vendor Name Northgate Office Solutions: found \u2713')
    else:
        issues.append(f'Northgate Office Solutions not found in row')

    # 5. INV-NGO-4471 (already confirmed)
    details.append('Invoice INV-NGO-4471: found \u2713')

    # 6. 1950.00 (PO Amount)
    result = find_exact_num_in_row(1950.0, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'PO Amount 1950.00: found {result[2]} \u2713')
    else:
        issues.append('Value 1950.00 (PO Amount) not found in row')

    # 7. 2030.00 (Invoice Amount)
    result = find_exact_num_in_row(2030.0, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'Invoice Amount 2030.00: found {result[2]} \u2713')
    else:
        issues.append('Value 2030.00 (Invoice Amount) not found in row')

    # 8. 97.50 (PO Unit Price)
    result = find_exact_num_in_row(97.5, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'PO Unit Price 97.50: found {result[2]} \u2713')
    else:
        issues.append('Value 97.50 (PO Unit Price) not found in row')

    # 9. 101.50 (Invoice Unit Price)
    result = find_exact_num_in_row(101.5, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'Invoice Unit Price 101.50: found {result[2]} \u2713')
    else:
        issues.append('Value 101.50 (Invoice Unit Price) not found in row')

    # 10. 4.10 (\u00b10.5%) - Price Variance %
    result = find_pct_in_row(4.1, tolerance=0.5, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'Price Variance % ~4.10: found {result[2]} \u2713')
    else:
        issues.append('Value ~4.10% (Price Variance %) not found in row')

    # 11. 4.00 (Price Variance $)
    result = find_exact_num_in_row(4.0, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'Price Variance $ 4.00: found {result[2]} \u2713')
    else:
        issues.append('Value 4.00 (Price Variance $) not found in row')

    # 12. 20 (PO Qty)
    result = find_exact_num_in_row(20.0, tolerance=0.5, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'PO Qty 20: found {result[2]} \u2713')
    else:
        issues.append('Value 20 (PO Qty) not found in row')

    # 13. 20 (Invoice Qty)
    result = find_exact_num_in_row(20.0, tolerance=0.5, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'Invoice Qty 20: found {result[2]} \u2713')
    else:
        issues.append('Second value of 20 (Invoice Qty) not found in row')

    # 14. 80.00 (Total Variance $)
    result = find_exact_num_in_row(80.0, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'Total Variance $ 80.00: found {result[2]} \u2713')
    else:
        issues.append('Value 80.00 (Total Variance $) not found in row')

    # 15. 4.10 (\u00b10.5%) - Total Variance %
    result = find_pct_in_row(4.1, tolerance=0.5, exclude_indices=used_indices)
    if result:
        used_indices.add(result[0])
        details.append(f'Total Variance % ~4.10: found {result[2]} \u2713')
    else:
        issues.append('Second value ~4.10% (Total Variance %) not found in row')

    # 16. "Pass" (Unit Price Result)
    if find_in_row_str('Pass'):
        details.append('Unit Price Result "Pass": found \u2713')
    else:
        issues.append('"Pass" not found in row')

    # 17. "Fail" (Total Amount Result)
    if find_in_row_str('Fail'):
        details.append('Total Amount Result "Fail": found \u2713')
    else:
        issues.append('"Fail" not found in row')

    # 18. "MATCH Hold" (Overall Result) - look for cell containing both "match" and "hold"
    match_hold_found = False
    for v in row_vals:
        vl = v.lower()
        if 'match' in vl and 'hold' in vl:
            match_hold_found = True
            details.append(f'Overall Result "MATCH Hold": found "{v}" \u2713')
            break
    if not match_hold_found:
        issues.append('"MATCH Hold" not found in row')

    # 19. "MATCH" for Hold Code - accept "MATCH" as a standalone cell or within hold code context
    match_code_found = False
    for v in row_vals:
        vl = v.lower().strip()
        # Accept exact "match" or common variants
        if vl == 'match':
            match_code_found = True
            details.append(f'Hold Code "MATCH": found "{v}" \u2713')
            break
    if not match_code_found:
        # Also accept '3-way match', 'three-way match', 'three way match', '3 way match'
        for v in row_vals:
            vl = v.lower().strip()
            if vl in ['3-way match', 'three-way match', 'three way match', '3 way match']:
                match_code_found = True
                details.append(f'Hold Code "MATCH": found "{v}" \u2713')
                break
    if not match_code_found:
        # Be even more lenient: accept if "match" appears in a cell that is NOT the "MATCH Hold" cell
        for v in row_vals:
            vl = v.lower().strip()
            if 'match' in vl and 'hold' not in vl:
                match_code_found = True
                details.append(f'Hold Code "MATCH": found "{v}" \u2713')
                break
    if not match_code_found:
        issues.append('"MATCH" (as Hold Code) not found in row')

    if issues:
        feedback = 'Match log row issues: ' + '; '.join(issues)
        if details:
            feedback += ' | Passed checks: ' + '; '.join(details)
        return {'pass': False, 'score': 0.0, 'feedback': feedback}

    return {'pass': True, 'score': 1.0, 'feedback': 'Match log row for INV-NGO-4471 verified: ' + '; '.join(details)}

from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    # Search for the file in workspace
    candidates = list(Path(workspace_path).rglob('match_result_INV-NGO-4471.txt'))

    if not candidates:
        # Try glob with case variations
        candidates = list(Path(workspace_path).rglob('match_result*4471*.txt'))

    if not candidates:
        return {'pass': False, 'score': 0.0, 'feedback': 'match_result_INV-NGO-4471.txt not found in workspace'}

    content = candidates[0].read_text(encoding='utf-8', errors='replace')
    content_lower = content.lower()
    issues = []
    found_items = []

    # 1. Check MATCH hold outcome
    match_hold_found = False
    if 'match hold' in content_lower or 'match_hold' in content_lower:
        match_hold_found = True
    elif 'match' in content_lower and 'hold' in content_lower:
        match_hold_found = True
    elif 'hold' in content_lower and ('three-way' in content_lower or '3-way' in content_lower or 'three way' in content_lower or '3 way' in content_lower):
        match_hold_found = True
    elif 'exception' in content_lower and ('hold' in content_lower or 'flag' in content_lower or 'fail' in content_lower):
        match_hold_found = True
    elif 'fail' in content_lower and 'match' in content_lower:
        match_hold_found = True
    elif 'mismatch' in content_lower and ('hold' in content_lower or 'exception' in content_lower or 'flag' in content_lower):
        match_hold_found = True
    elif 'on hold' in content_lower:
        match_hold_found = True
    elif 'placed' in content_lower and 'hold' in content_lower:
        match_hold_found = True

    if match_hold_found:
        found_items.append('MATCH hold outcome')
    else:
        issues.append('MATCH hold outcome not mentioned')

    # 2. Check $80 variance or ~4.1%
    has_80 = bool(re.search(r'\$?80(\.00)?', content))
    has_4_1 = bool(re.search(r'4\.0[0-9]|4\.1[0-9]?', content))
    if has_80 or has_4_1:
        parts = []
        if has_80:
            parts.append('$80 variance')
        if has_4_1:
            parts.append('~4.1% figure')
        found_items.append(' and '.join(parts))
    else:
        issues.append('Neither $80.00 variance nor ~4.1% figure found in file')

    # 3. Check threshold references (±$50 and/or ±2%)
    has_50 = bool(re.search(r'\$?50', content))
    has_2pct = bool(re.search(r'2\s*%|±\s*2|\+/?-\s*2|2\s*percent', content_lower))
    if has_50 or has_2pct:
        parts = []
        if has_50:
            parts.append('$50 threshold')
        if has_2pct:
            parts.append('2% threshold')
        found_items.append(' and '.join(parts))
    else:
        issues.append('Neither $50 threshold nor 2% threshold referenced in file')

    # 4. Check unit price check passing
    unit_price_found = False
    if 'unit price' in content_lower or 'unit_price' in content_lower:
        unit_price_found = True
    elif 'per-unit' in content_lower or 'per unit' in content_lower:
        unit_price_found = True
    elif 'price' in content_lower and any(w in content_lower for w in ['pass', 'passed', 'match', 'matched', 'correct', 'ok', 'good', 'confirmed', 'agree', 'consistent', 'verified', 'check']):
        unit_price_found = True
    elif 'line item' in content_lower and any(w in content_lower for w in ['pass', 'passed', 'match', 'matched', 'correct', 'verified', 'check']):
        unit_price_found = True

    if unit_price_found:
        found_items.append('unit price check')
    else:
        issues.append('Unit price check pass not mentioned')

    # 5. Check next action: vendor email / price clarification
    has_vendor_action = False
    # Multiple ways this could be expressed
    if ('email' in content_lower or 'contact' in content_lower or 'notify' in content_lower or 'reach out' in content_lower or 'send' in content_lower or 'communicate' in content_lower) and ('vendor' in content_lower or 'supplier' in content_lower or 'northgate' in content_lower):
        has_vendor_action = True
    if 'clarif' in content_lower or 'discrepanc' in content_lower or 'dispute' in content_lower or 'reconcil' in content_lower:
        has_vendor_action = True
    if 'vendor' in content_lower and ('price' in content_lower or 'amount' in content_lower or 'invoice' in content_lower or 'review' in content_lower or 'resolution' in content_lower or 'resolve' in content_lower):
        has_vendor_action = True
    if 'northgate' in content_lower and ('contact' in content_lower or 'email' in content_lower or 'notify' in content_lower or 'clarif' in content_lower or 'reach' in content_lower):
        has_vendor_action = True
    # Check for SOP step references as alternative evidence
    if re.search(r'6\.1|step\s*2\s*b|2b', content_lower):
        has_vendor_action = True
    # Accept general next steps mentioning investigation/follow-up with vendor
    if ('next step' in content_lower or 'action' in content_lower or 'follow' in content_lower) and ('vendor' in content_lower or 'northgate' in content_lower or 'supplier' in content_lower):
        has_vendor_action = True

    if has_vendor_action:
        found_items.append('vendor email/price clarification next step')
    else:
        issues.append('Vendor email/price clarification next step not mentioned')

    # Scoring: partial credit
    total_checks = 5
