        # Check vendor ID (case insensitive)
        if 'v-00229' not in text_lower:
            msg_issues.append('vendor ID V-00229 missing')

        # PO price: accept $97.50 or unit-level equivalents, or total $1,950.00
        has_po_price = any(x in text for x in ['97.50', '97.5', '1950', '1,950'])
        if not has_po_price:
            msg_issues.append('PO price ($97.50 or $1,950.00) missing')

        # Invoice price: accept $101.50 or total $2,030.00
