        if not has_inv_price:
            msg_issues.append('Invoice price ($101.50 or $2,030.00) missing')

        # Variance ~4.10% (±0.5% so accept 3.6% to 4.6%)
        # Look for percentage patterns in text
        pct_matches = re.findall(r'(\d+\.\d+)\s*%', text)
        has_variance = False
        for pct_str in pct_matches:
            try:
                pct_val = float(pct_str)
                if 3.6 <= pct_val <= 4.6:
