                    break
            except ValueError:
                pass
        # Also accept integer-like "4%" loosely
        if not has_variance:
            int_pct_matches = re.findall(r'(\d+)\s*%', text)
            for pct_str in int_pct_matches:
                try:
                    pct_val = float(pct_str)
                    if 3.6 <= pct_val <= 4.6:
                        has_variance = True
                        break
                except ValueError:
                    pass
        if not has_variance:
            msg_issues.append('Variance percentage (~4.10% \u00b10.5%) missing')

        if not msg_issues:
            return {'pass': True, 'score': 1.0, 'feedback': f'#ap-exceptions contains a valid PRICE VARIANCE message for INV-NGO-4471 with all required fields. Message text: {text[:300]}'}
