from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'No external_services_path provided; cannot check mailbox.json for sent email'}

    mailbox_file = Path(external_services_path) / 'mailbox.json'
    if not mailbox_file.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found'}

    with open(mailbox_file, 'r', encoding='utf-8') as f:
        data = json.load(f)

    emails = data.get('emails', [])
    sent_emails = [e for e in emails if e.get('folder', '').lower() == 'sent']

    target_invoice = 'INV-NGO-4471'

    # Find emails sent to @northgateoffice.com with the invoice number in the subject
    matching = []
    for e in sent_emails:
        to_addr = e.get('to_addr', '').lower()
        subject = e.get('subject', '')
        if '@northgateoffice.com' in to_addr and target_invoice.lower() in subject.lower():
            matching.append(e)

    if not matching:
        return {'pass': False, 'score': 0.0, 'feedback': f'No sent email found to @northgateoffice.com with {target_invoice} in subject. Sent emails: {[{"to": e.get("to_addr"), "subject": e.get("subject")} for e in sent_emails]}'}

    issues_all = []
    for email in matching:
        subject = email.get('subject', '')
        body = email.get('body_text', '') or email.get('body', '') or ''
        body_lower = body.lower()
        subject_lower = subject.lower()
        email_issues = []

        # (1) Subject must contain "Price Discrepancy"
        if 'price discrepancy' not in subject_lower:
            email_issues.append(f'Subject does not contain "Price Discrepancy". Subject was: "{subject}"')

        # (2) Body must reference PO price: $1950.00 or $97.50 (total or unit)
        po_price_found = False
        for token in ['1950.00', '1950', '1,950.00', '1,950', '97.50', '97.5']:
            if token in body:
                po_price_found = True
                break
        if not po_price_found:
            email_issues.append('PO price ($1950.00 or $97.50) not found in body')

        # (3) Body must reference invoiced price: $2030.00 or $101.50 (total or unit)
        inv_price_found = False
        for token in ['2030.00', '2030', '2,030.00', '2,030', '101.50', '101.5']:
            if token in body:
                inv_price_found = True
                break
        if not inv_price_found:
            email_issues.append('Invoiced price ($2030.00 or $101.50) not found in body')

        # (4) Body must reference variance percentage ~4.10% (accept 3.60% to 4.60%, i.e. 4.10 +/- 0.5)
        variance_found = False
        # Search for any percentage-like number in the body and check range
        pct_pattern = re.compile(r'(\d+\.\d+)\s*%')
        for m in pct_pattern.finditer(body):
            val = float(m.group(1))
            if 3.60 <= val <= 4.60:
                variance_found = True
                break
        # Also accept bare mentions like "4.1" or "4.10" without % sign near context words
        if not variance_found:
            bare_pattern = re.compile(r'\b(\d+\.\d+)\b')
            for m in bare_pattern.finditer(body):
                val = float(m.group(1))
                if 3.60 <= val <= 4.60:
                    variance_found = True
                    break
        if not variance_found:
            email_issues.append('Variance percentage (~4.10%, +/-0.5%) not found in body')

        if not email_issues:
            return {'pass': True, 'score': 1.0, 'feedback': f'Sent email to @northgateoffice.com found with correct subject containing "Price Discrepancy" and "{target_invoice}", and body references PO price, invoice price, and variance ~4.1%.'}
        issues_all.append(f'Email (subject="{subject}"): ' + '; '.join(email_issues))

    return {'pass': False, 'score': 0.0, 'feedback': 'Matching sent emails have issues: ' + ' | '.join(issues_all)}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    workspace_path = Path(workspace_path)

    # Locate the final slack_data.json
    final_candidates = []
    if external_services_path:
        final_candidates.append(Path(external_services_path) / "slack_data.json")
    final_candidates.append(workspace_path / "external_data" / "final" / "slack_data.json")

    final_slack_path = None
    for p in final_candidates:
        if p.exists():
            final_slack_path = p
            break

    if final_slack_path is None:
        return {"pass": True, "score": 1.0, "feedback": "No final slack_data.json found; cannot confirm any messages were added, so passing by default (generous interpretation)."}

    # Load final data
    try:
        with open(final_slack_path, 'r', encoding='utf-8') as f:
            final_data = json.load(f)
    except Exception as e:
        return {"pass": True, "score": 1.0, "feedback": f"Could not parse final slack_data.json ({e}); passing generously."}

    # Helper to unwrap possible nested structure
    def unwrap(data):
        if isinstance(data, dict) and "slack_data" in data:
            return data["slack_data"]
        return data

    final_data = unwrap(final_data)

    # The three channels we care about
    target_channel_names = {"ap-escalations", "ap-payments", "ap-approvals"}

    # Build a map from channel name -> channel id
    channels_info = final_data.get("channels", {}) if isinstance(final_data, dict) else {}
    if not isinstance(channels_info, dict):
        return {"pass": True, "score": 1.0, "feedback": "No channels dict found in slack_data.json; pass by default."}

    channel_name_to_id = {}
    for channel_id, channel_info in channels_info.items():
        if isinstance(channel_info, dict):
            name = (channel_info.get("name", "") or "").strip().lstrip("#").lower()
            if name in target_channel_names:
                channel_name_to_id[name] = channel_id

    if not channel_name_to_id:
        return {"pass": True, "score": 1.0, "feedback": "None of the target channels (#ap-escalations, #ap-payments, #ap-approvals) found in final slack_data.json; pass by default."}

    messages_data = final_data.get("messages", {}) if isinstance(final_data, dict) else {}
    if not isinstance(messages_data, dict):
        messages_data = {}

    invoice_ref = "INV-NGO-4471"
    # Use a case-insensitive pattern that matches the invoice number with or without dashes
    pattern = re.compile(re.escape(invoice_ref), re.IGNORECASE)

    violations = []

    for chan_name, chan_id in channel_name_to_id.items():
        chan_msgs = messages_data.get(chan_id, [])
        if not isinstance(chan_msgs, list):
            continue
        for msg in chan_msgs:
            if not isinstance(msg, dict):
                continue
            text = msg.get("text", "") or ""
            if pattern.search(text):
                user = msg.get("user", "unknown")
                preview = text[:150]
                violations.append(f"  - #{chan_name} (channel {chan_id}): User {user}: {preview}")

    if violations:
        detail = "\n".join(violations)
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"FAIL: Found {len(violations)} message(s) referencing {invoice_ref} in the restricted channels:\n{detail}"
        }

    checked = ", ".join([f"#{n} ({channel_name_to_id[n]})" for n in sorted(channel_name_to_id.keys())])
    return {
        "pass": True,
        "score": 1.0,
        "feedback": f"PASS: No messages referencing {invoice_ref} found in checked channels: {checked}."
    }

from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "ap_ledger.xlsx"

    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File '{file_path}' does not exist."}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open '{file_path}': {e}"}

    # Check that 'PO Register' sheet exists
    sheet_names = wb.sheetnames
    po_register_sheet = None
    for name in sheet_names:
        if name.strip().lower() == "po register":
            po_register_sheet = wb[name]
            break

    if po_register_sheet is None:
        wb.close()
        return {"pass": False, "score": 0.0, "feedback": f"Sheet 'PO Register' not found in ap_ledger.xlsx. Sheets found: {sheet_names}"}

    def parse_numeric(val):
        """Parse a cell value to a float, stripping dollar signs, commas, whitespace."""
        if val is None:
            return None
        if isinstance(val, (int, float)):
            return float(val)
        s = str(val).strip()
        # Remove dollar sign, commas, whitespace
        s = s.replace('$', '').replace(',', '').strip()
        try:
            return float(s)
        except (ValueError, TypeError):
            return None

    g5_val = po_register_sheet['G5'].value
    i5_val = po_register_sheet['I5'].value

    g5_num = parse_numeric(g5_val)
    i5_num = parse_numeric(i5_val)

    issues = []
    passed_checks = []

    # Check G5 = 97.50 with ±1% tolerance
    expected_g5 = 97.50
    if g5_num is None:
        issues.append(f"G5: expected {expected_g5}, but got '{g5_val}' (could not parse as number)")
    elif abs(g5_num - expected_g5) > expected_g5 * 0.01:
        issues.append(f"G5: expected {expected_g5}, but got {g5_num} (raw: '{g5_val}')")
    else:
        passed_checks.append(f"G5={g5_num} (expected {expected_g5})")

    # Check I5 = 1950.00 with ±1% tolerance
    expected_i5 = 1950.00
    if i5_num is None:
        issues.append(f"I5: expected {expected_i5}, but got '{i5_val}' (could not parse as number)")
    elif abs(i5_num - expected_i5) > expected_i5 * 0.01:
        issues.append(f"I5: expected {expected_i5}, but got {i5_num} (raw: '{i5_val}')")
    else:
        passed_checks.append(f"I5={i5_num} (expected {expected_i5})")

    wb.close()

    if issues:
        score = len(passed_checks) / (len(passed_checks) + len(issues))
        return {
            "pass": False,
            "score": score,
            "feedback": f"PO Register cell value mismatches: {'; '.join(issues)}. Passed: {'; '.join(passed_checks) if passed_checks else 'none'}."
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": f"PO Register sheet verified successfully. {'; '.join(passed_checks)}."
    }

